class Solution {
public:
    bool validUtf8(vector<int>& data) {
        int i = 0, n = data.size();
        while (i < n) {
            int need = 0;
            if ((data[i] >> 7) == 0) i++;
            else if ((data[i] >> 5) == 0b110) { need = 1; i++; }
            else if ((data[i] >> 4) == 0b1110) { need = 2; i++; }
            else if ((data[i] >> 3) == 0b11110) { need = 3; i++; }
            else return false;
            for (int k = 0; k < need; k++, i++)
                if (i >= n || (data[i] >> 6) != 0b10) return false;
        }
        return true;
    }
};

